const GEMINI_VEO_MODEL = 'veo-3.1-generate-preview';

type GeminiImageResponse = {
  candidates?: Array<{
    content?: {
      parts?: Array<{
        text?: string;
        inlineData?: {
          mimeType?: string;
          data?: string;
        };
      }>;
    };
  }>;
};

type VeoOperation = {
  name?: string;
