          stackItems: result.images.slice(0, 3).map((url, index) => ({
            label: `ref ${index + 1}`,
            tint:
              index % 3 === 0
                ? 'from-rose-200 to-orange-100'
                : index % 3 === 1
                  ? 'from-sky-200 to-cyan-100'
                  : 'from-emerald-200 to-lime-100',
