import type { SupabaseClient } from '@supabase/supabase-js';

import { CAMPAIGN_CONFIG_ID, CAMPAIGN_CONFIG_TABLE } from '../supabase/constants';
import type { ChoiceConfig } from '../../components/workspace/ChoiceScreen';

type StoredCampaignConfigRow = {
  id: string;
  config: ChoiceConfig;
  updated_at?: string;
};

export async function loadCampaignConfig(client: SupabaseClient): Promise<ChoiceConfig | null> {
  const { data, error } = await client
    .from(CAMPAIGN_CONFIG_TABLE)
    .select('id, config, updated_at')
    .eq('id', CAMPAIGN_CONFIG_ID)
    .maybeSingle<StoredCampaignConfigRow>();

  if (error) {
    throw error;
  }

  if (!data || !data.config || Object.keys(data.config).length === 0) {
    return null;
  }

  return data.config;
}

export async function saveCampaignConfig(
  client: SupabaseClient,
  config: ChoiceConfig,
): Promise<void> {
  const { error } = await client.from(CAMPAIGN_CONFIG_TABLE).upsert({
    id: CAMPAIGN_CONFIG_ID,
    config,
  });

  if (error) {
    throw error;
  }
}

'use client';

import { useCallback, useEffect, useRef, useState } from 'react';

import type { ChoiceConfig } from '../components/workspace/ChoiceScreen';
import { loadCampaignConfig, saveCampaignConfig } from '../lib/campaign/persistence';
import { getSupabaseBrowserClient, isSupabaseConfigured } from '../lib/supabase/client';

type PersistenceStatus = 'local-only' | 'loading' | 'ready' | 'saving' | 'saved' | 'error';

export function useChoiceConfig() {
  const supabase = getSupabaseBrowserClient();
  const configured = isSupabaseConfigured();

  const [config, setConfig] = useState<ChoiceConfig | null>(null);
  const [status, setStatus] = useState<PersistenceStatus>(configured ? 'loading' : 'local-only');
  const [error, setError] = useState<string | null>(null);

  const hasLoadedRef = useRef(false);
  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Load on mount
  useEffect(() => {
    if (!supabase) return;

    let active = true;

    async function hydrate() {
      setStatus('loading');
      setError(null);
      try {
        const loaded = await loadCampaignConfig(supabase!);
        if (!active) return;
        if (loaded) setConfig(loaded);
        hasLoadedRef.current = true;
        setStatus('saved');
      } catch (err) {
        if (!active) return;
        hasLoadedRef.current = true;
        setStatus('error');
        setError(err instanceof Error ? err.message : 'Failed to load campaign config');
      }
    }

    hydrate();
    return () => { active = false; };
  }, [supabase]);

  // Debounced save whenever config changes post-load
  useEffect(() => {
    if (!supabase || !hasLoadedRef.current || !config) return;

    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    setStatus('saving');

    saveTimerRef.current = setTimeout(async () => {
      try {
        await saveCampaignConfig(supabase, config);
        setStatus('saved');
        setError(null);
      } catch (err) {
        setStatus('error');
        setError(err instanceof Error ? err.message : 'Failed to save campaign config');
      }
    }, 700);

    return () => {
      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    };
  }, [config, supabase]);

  const updateConfig = useCallback((next: ChoiceConfig) => {
    if (!hasLoadedRef.current) hasLoadedRef.current = true;
    setConfig(next);
  }, []);

  return { config, updateConfig, status, error };
}

